11	/// Тип радиации
12	enum RadiationType: Equatable, Codable, Hashable, Identifiable {
13	    
14	    var id: Self {
15	        self
16	    }
17	    
18	    enum Level: String, Equatable, Codable {
19	        case countRate
20	        case doseRate
21	        
22	        var accentColor: Color {
23	            switch self {
24	            case .countRate:
25	                .accentGreen
26	            case .doseRate:
27	                .accentBlue
28	            }
29	        }
30	        
31	        var title: LocalizedStringResource {
32	            switch self {
33	            case .countRate:
34	                .Localization.countRate
35	            case .doseRate:
36	                .Localization.doseRate
37	            }
38	        }
39	        
40	        var unit: LocalizedStringResource {
41	            switch self {
42	            case .countRate:
43	                .Localization.cps
44	            case .doseRate:
45	                .Localization.μSvH
46	            }
47	        }
48	    }
49	    
50	    /// Уровни радиации
51	    case radiationLevel(Level)
52	    /// Доза
53	    case dose
54	    
55	    var title: LocalizedStringResource {
56	        switch self {
57	        case .radiationLevel(let level):
58	            level.title
59	        case .dose:
60	            .Localization.dose
61	        }
62	    }
63	    
64	    var unit: LocalizedStringResource {
65	        switch self {
66	        case .radiationLevel(let level):
67	            level.unit
68	        case .dose:
69	            .Localization.μSv
70	        }
71	    }
72	    
73	    var defaultMaxValue: Decimal {
74	        switch self {
75	        case .radiationLevel(let level):
76	            switch level {
77	            case .countRate:
78	                50000
79	            case .doseRate:
80	                1000
81	            }
82	        case .dose:
83	            10000000
84	        }
85	    }
86	    
87	    func unitByValue(value: Decimal) -> LocalizedStringResource {
88	        if self == .dose {
89	            if value >= 1_000_000 {
90	                return .Localization.sv
91	            } else if value >= 1000 {
92	                return .Localization.mSv
93	            }
94	        }
95	        return self.unit
96	    }
97	    
98	    func scale(value: Decimal) -> Decimal {
99	        if self == .dose {
100	            if value >= 1_000_000 {
101	                return value / 1_000_000
102	            } else if value >= 1000 {
103	                return value / 1000
104	            }
105	        }
106	        return value
107	    }
108	}
