110	// MARK: - Сustom Decodable
111	extension RadiationType {
112	
113	    private enum RadiationKey: String, CodingKey {
114	        case radiationLevel
115	        case dose
116	    }
117	    
118	    init(from decoder: Decoder) throws {
119	        let container = try decoder.container(keyedBy: RadiationKey.self)
120	
121	        if container.contains(.dose) {
122	            self = .dose
123	            return
124	        }
125	
126	        if container.contains(.radiationLevel) {
127	            if let level = try? container.decode([String: String].self, forKey: .radiationLevel) {
128	                for value in level.values {
129	                    if let level = RadiationType.Level(rawValue: value) {
130	                        self = .radiationLevel(level)
131	                        return
132	                    }
133	                }
134	            }
135	        }
136	
137	        // Это жуткий костыль, чтобы убрать падения, при извлечении данных в SwiftData throw приводит к падению
138	        self = .radiationLevel(.countRate)
139	    }
140	}
