21	final class UpdateAlarmsUseCaseImpl: UpdateAlarmsUseCase {
22	
23	    @Injected(\.deviceManager) private var deviceManager
24	    @Injected(\.deviceContainer) private var deviceContainer
25	
26	    func update(radiationType: RadiationType, level1: Decimal?, level2: Decimal?) async {
27	        let doseAlarmMultiplier = deviceContainer.current?.configurationSettings.doseAlarmMultiplier ?? 1
28	        if let level1 {
29	            await write(
30	                setting: radiationType.deviceSettingsLevel1,
31	                value: Alarm.Level.encode(value: level1, for: radiationType, doseAlarmMultiplier: doseAlarmMultiplier)
32	            )
33	        }
34	        if let level2 {
35	            await write(
36	                setting: radiationType.deviceSettingsLevel2,
37	                value: Alarm.Level.encode(value: level2, for: radiationType, doseAlarmMultiplier: doseAlarmMultiplier)
38	            )
39	        }
40	    }
41	
42	    private func write(setting: BluetoothCommandOperation, value: UInt32) async {
43	        await deviceManager.send(command: SettingsCommand(
44	            setting: setting, action: .write, payload: value
45	        ))
46	    }
47	}
